package main

import (
	"errors"
	"fmt"
	"os/exec"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host the given number of times and returns the average latency in milliseconds.
// It uses the system 'ping' command via os/exec and parses the output to extract the average RTT.
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}

	// Execute ping command directly without shell to avoid injection risks and quoting issues
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("ping command failed: %w, output: %s", err, string(output))
	}

	// Search for statistics line containing min/avg/max (case-insensitive)
	lines := strings.Split(string(output), "\n")
	for _, line := range lines {
		if strings.Contains(strings.ToLower(line), "min/avg/max") {
			// Split line at first '=' to isolate statistics values
			parts := strings.SplitN(line, "=", 2)
			if len(parts) < 2 {
				continue
			}

			// Extract first field after '=' (contains slash-separated values)
			fields := strings.Fields(parts[1])
			if len(fields) == 0 {
				continue
			}

			// Split values by '/' and extract average (second value)
			nums := strings.Split(fields[0], "/")
			if len(nums) < 2 {
				continue
			}

			avgStr := strings.TrimSpace(nums[1])
			avg, parseErr := strconv.ParseFloat(avgStr, 64)
			if parseErr != nil {
				return 0, fmt.Errorf("failed to parse average latency value '%s': %w", avgStr, parseErr)
			}
			return avg, nil
		}
	}

	return 0, errors.New("could not find RTT statistics line in ping output")
}

