package main

import (
	"fmt"
	"os/exec"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host the given number of times and returns
// the average latency in milliseconds. Uses system 'ping' command with -c flag
// (Unix-like systems). Returns error if validation fails, command execution fails,
// or output cannot be parsed.
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, fmt.Errorf("count must be a positive integer")
	}
	if host == "" {
		return 0, fmt.Errorf("host cannot be empty")
	}

	// Execute ping command: ping -c <count> <host>
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)
	output, cmdErr := cmd.CombinedOutput()

	// Parse output from end to find statistics line containing "min/avg/max"
	lines := strings.Split(string(output), "\n")
	for i := len(lines) - 1; i >= 0; i-- {
		line := lines[i]
		if strings.Contains(line, "min/avg/max") {
			fields := strings.Fields(line)
			if len(fields) < 2 {
				continue
			}
			// Time values field is second-to-last (before "ms" unit)
			timeField := fields[len(fields)-2]
			parts := strings.Split(timeField, "/")
			if len(parts) < 2 {
				continue
			}
			// Average is second value in min/avg/max/stddev group
			avgStr := parts[1]
			avg, parseErr := strconv.ParseFloat(avgStr, 64)
			if parseErr != nil {
				continue
			}
			return avg, nil
		}
	}

	// Parsing failed - determine appropriate error message
	if cmdErr != nil {
		return 0, fmt.Errorf("ping command execution failed: %w. Output: %s", cmdErr, string(output))
	}
	return 0, fmt.Errorf("could not parse average latency from ping output. Full output: %s", string(output))
}

func main() {
	// Minimal main function required for compilable package main.
	// Utility function MeasureLatency is intended for programmatic use.
}

