package main

import (
	"fmt"
	"os"
	"os/exec"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host the given number of times and returns
// the average latency in milliseconds. Uses system 'ping' command with Linux syntax.
// Returns error if count is invalid, command fails, or output cannot be parsed.
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, fmt.Errorf("count must be a positive integer")
	}

	// Construct ping command for Linux systems (-c for count, -q for quiet summary output)
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), "-q", host)
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("ping command failed: %w. Output: %s", err, string(output))
	}

	// Parse output to find latency statistics line containing "min/avg/max"
	lines := strings.Split(string(output), "\n")
	for _, line := range lines {
		if strings.Contains(line, "min/avg/max") {
			// Split line at '=' to isolate statistics values
			parts := strings.Split(line, "=")
			if len(parts) < 2 {
				continue
			}

			// Extract and clean the statistics portion (e.g., " 10.123/20.456/30.789/5.123 ms")
			statsSection := strings.TrimSpace(parts[1])
			tokens := strings.Fields(statsSection)
			if len(tokens) == 0 {
				continue
			}

			// Split the numeric values (format: min/avg/max/mdev)
			values := strings.Split(tokens[0], "/")
			if len(values) < 2 {
				continue
			}

			// Parse average value (second field)
			avg, parseErr := strconv.ParseFloat(values[1], 64)
			if parseErr != nil {
				return 0, fmt.Errorf("failed to parse average latency value '%s': %w", values[1], parseErr)
			}
			return avg, nil
		}
	}

	return 0, fmt.Errorf("could not find latency statistics in ping output. Full output: %s", string(output))
}

func main() {
	if len(os.Args) != 3 {
		fmt.Fprintf(os.Stderr, "Usage: %s <host> <count>\n", os.Args[0])
		os.Exit(1)
	}

	host := os.Args[1]
	count, err := strconv.Atoi(os.Args[2])
	if err != nil {
		fmt.Fprintf(os.Stderr, "Error: invalid count value '%s' - must be integer\n", os.Args[2])
		os.Exit(1)
	}

	avgLatency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Fprintf(os.Stderr, "Latency measurement failed: %v\n", err)
		os.Exit(1)
	}

	// Output average latency formatted to 3 decimal places (standard for latency)
	fmt.Printf("%.3f\n", avgLatency)
}

