package main

import (
	"fmt"
	"os"
	"os/exec"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host the given number of times and returns
// the average round-trip latency in milliseconds. Uses system ping command via os/exec.
// Returns error if ping fails, output cannot be parsed, or inputs are invalid.
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, fmt.Errorf("count must be a positive integer")
	}
	if host == "" {
		return 0, fmt.Errorf("host cannot be empty")
	}

	// Execute ping command (Unix-style: Linux/macOS compatible)
	// Note: Relies on system ping command output containing "min/avg/max" statistics line
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("ping command failed: %w, output: %s", err, string(output))
	}

	// Parse ping output for RTT statistics line (e.g., "rtt min/avg/max/mdev = ...")
	lines := strings.Split(string(output), "\n")
	for _, line := range lines {
		if strings.Contains(strings.ToLower(line), "min/avg/max") {
			// Extract value section after "="
			parts := strings.SplitN(line, "=", 2)
			if len(parts) < 2 {
				continue
			}
			statsSection := strings.TrimSpace(parts[1])

			// Isolate numeric values (before unit "ms")
			valueTokens := strings.Fields(statsSection)
			if len(valueTokens) == 0 {
				continue
			}
			numbersStr := valueTokens[0]

			// Split numeric values (format: min/avg/max/mdev)
			values := strings.Split(numbersStr, "/")
			if len(values) < 2 {
				continue
			}

			// Parse average value (second field)
			avgStr := strings.TrimSpace(values[1])
			avg, parseErr := strconv.ParseFloat(avgStr, 64)
			if parseErr != nil {
				return 0, fmt.Errorf("failed to parse average latency value '%s': %w", avgStr, parseErr)
			}
			return avg, nil
		}
	}

	return 0, fmt.Errorf("could not find latency statistics in ping output (expected 'min/avg/max' line)")
}

func main() {
	if len(os.Args) != 3 {
		fmt.Fprintf(os.Stderr, "Usage: %s <host> <count>\n", os.Args[0])
		os.Exit(1)
	}

	count, err := strconv.Atoi(os.Args[2])
	if err != nil {
		fmt.Fprintf(os.Stderr, "Invalid count: %v\n", err)
		os.Exit(1)
	}

	avgLatency, err := MeasureLatency(os.Args[1], count)
	if err != nil {
		fmt.Fprintf(os.Stderr, "Error measuring latency: %v\n", err)
		os.Exit(1)
	}

	fmt.Printf("%.3f\n", avgLatency)
}

