import (
	"fmt"
	"os"
	"os/exec"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host the given number of times and returns the average latency in milliseconds.
// Uses the system's ping command via os/exec. Designed for Unix-like systems (Linux/macOS) where ping uses -c flag.
func MeasureLatency(host string, count int) (float64, error) {
	// Validate inputs
	if count <= 0 {
		return 0, fmt.Errorf("count must be a positive integer")
	}
	if host == "" {
		return 0, fmt.Errorf("host cannot be empty")
	}

	// Construct ping command for Unix-like systems (Linux/macOS)
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("ping command failed: %w, output: %s", err, string(output))
	}

	// Parse output for latency statistics line (contains "min/avg/max")
	outputStr := string(output)
	lines := strings.Split(outputStr, "\n")
	for _, line := range lines {
		if strings.Contains(line, "min/avg/max") {
			// Split line to extract statistics values
			parts := strings.Split(line, "=")
			if len(parts) < 2 {
				return 0, fmt.Errorf("unexpected ping output format in line: %s", line)
			}

			// Clean and split the statistics portion
			statsPart := strings.TrimSpace(parts[1])
			statsTokens := strings.Split(statsPart, " ")
			if len(statsTokens) == 0 {
				return 0, fmt.Errorf("invalid statistics format: %s", statsPart)
			}

			// Extract numeric values (min/avg/max/mdev or similar)
			numStr := statsTokens[0]
			numParts := strings.Split(numStr, "/")
			if len(numParts) < 2 {
				return 0, fmt.Errorf("unexpected statistics value count in: %s", numStr)
			}

			// Parse average latency (second value in min/avg/max sequence)
			avgStr := numParts[1]
			avg, parseErr := strconv.ParseFloat(avgStr, 64)
			if parseErr != nil {
				return 0, fmt.Errorf("failed to parse average latency '%s': %v", avgStr, parseErr)
			}
			return avg, nil
		}
	}

	return 0, fmt.Errorf("latency statistics not found in ping output; full output:\n%s", outputStr)
}

func main() {
	if len(os.Args) != 3 {
		fmt.Fprintf(os.Stderr, "Usage: %s <host> <count>\n", os.Args[0])
		os.Exit(1)
	}

	host := os.Args[1]
	count, err := strconv.Atoi(os.Args[2])
	if err != nil {
		fmt.Fprintf(os.Stderr, "Error: invalid count '%s' - must be integer\n", os.Args[2])
		os.Exit(1)
	}

	avgLatency, err := MeasureLatency(host, count)
