fix.generatedCode:
package main

import (
	"errors"
	"fmt"
	"os/exec"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host the given number of times and returns the average latency in milliseconds.
// It uses the system 'ping' command via os/exec and parses the output to extract the average RTT.
// Note: This implementation is designed for Linux systems where ping output contains "rtt min/avg/max" statistics.
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}

	// Execute ping command directly (Linux-specific: -c specifies count)
	// Avoids shell injection risks and bash dependency by passing arguments directly
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("ping command failed: %w; output: %s", err, string(output))
	}

	// Search for RTT statistics line in output
	outputStr := string(output)
	var statsLine string
	for _, line := range strings.Split(outputStr, "\n") {
		if strings.Contains(line, "rtt min/avg/max") {
			statsLine = line
			break
		}
	}

	if statsLine == "" {
		return 0, errors.New("RTT statistics line not found in ping output (ensure host is reachable and system is Linux-compatible)")
	}

	// Parse statistics line: "rtt min/avg/max/mdev = 0.038/0.041/0.045/0.005 ms"
	parts := strings.SplitN(statsLine, "=", 2)
	if len(parts) < 2 {
		return 0, errors.New("invalid statistics line format: missing '=' separator")
	}

	// Extract numeric values portion (before "ms" unit)
	valuesSection := strings.TrimSpace(parts[1])
	valuesSection = strings.Split(valuesSection, " ")[0] // Isolate "min/avg/max/mdev" values

	// Split values by slash and validate
	values := strings.Split(valuesSection, "/")
	if len(values) < 2 {
		return 0, fmt.Errorf("unexpected value format in statistics line: %s", valuesSection)
	}

	// Parse average latency (second value: min=0, avg=1)
	avg, err := strconv.ParseFloat(strings.TrimSpace(values[1]), 64)
	if err != nil {
		return 0, fmt.Errorf("failed to parse average latency value '%s': %w", values[1], err)
	}

	return avg, nil
}

