package main

import (
	"errors"
	"fmt"
	"os/exec"
	"regexp"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host the given number of times and returns the average latency in milliseconds.
// It uses the system 'ping' command via os/exec and parses the output to extract the average RTT.
func MeasureLatency(host string, count int) (float64, error) {
	// Validate host: non-empty and cannot start with dash (prevents option injection)
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if strings.HasPrefix(host, "-") {
		return 0, errors.New("host cannot start with a dash character")
	}

	// Validate count: prevent resource exhaustion and ensure reasonable bounds
	if count <= 0 || count > 100 {
		return 0, errors.New("count must be between 1 and 100")
	}

	// Execute ping directly without shell invocation to prevent command injection
	// Arguments passed as separate values avoid shell interpretation of special characters
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)
	output, err := cmd.CombinedOutput()
	if err != nil {
		// Truncate output in error message to prevent log injection/excessive logging
		truncatedOutput := string(output)
		if len(truncatedOutput) > 512 {
			truncatedOutput = truncatedOutput[:512] + "..."
		}
		return 0, fmt.Errorf("failed to execute ping: %w (output: %s)", err, truncatedOutput)
	}

	// Parse RTT statistics line
	outputStr := string(output)
	lines := strings.Split(outputStr, "\n")
	var statsLine string
	for _, line := range lines {
		if strings.Contains(line, "rtt min/avg/max") {
			statsLine = line
			break
		}
	}

	if statsLine == "" {
		return 0, errors.New("could not find RTT statistics in ping output")
	}

	// Extract average latency using regex (Linux ping format)
	// Example: rtt min/avg/max/mdev = 12.345/23.456/34.567/5.678 ms
	re := regexp.MustCompile(`rtt min/avg/max/mdev = [\d.]+/([\d.]+)/[\d.]+/[\d.]+ ms`)
	matches := re.FindStringSubmatch(statsLine)
	if len(matches) < 2 {
		return 0, errors.New("failed to parse average latency from ping output")
	}

	avg, err := strconv.ParseFloat(matches[1], 64)
	if err != nil {
		return 0, fmt.Errorf("failed to convert average latency to float: %w", err)
	}

	return avg, nil
}

