package main

import (
	"fmt"
	"os"
	"os/exec"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host the given number of times and returns
// the average latency in milliseconds. Uses system ping command and parses output.
// Designed for Unix-like systems (Linux/macOS) where ping uses -c flag and outputs
// min/avg/max statistics in summary line.
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, fmt.Errorf("count must be a positive integer")
	}

	// Execute ping command: -c specifies count, host is target
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("ping command failed: %w. Output: %s", err, string(output))
	}

	// Parse output to find summary line containing latency statistics
	lines := strings.Split(string(output), "\n")
	var summaryLine string
	for _, line := range lines {
		// Match both Linux ("rtt min/avg/max/mdev") and macOS ("round-trip min/avg/max/stddev")
		if strings.Contains(strings.ToLower(line), "min/avg/max") {
			summaryLine = line
		}
	}
	if summaryLine == "" {
		return 0, fmt.Errorf("could not find latency summary line in ping output")
	}

	// Split line at first '=' to separate label from values
	parts := strings.SplitN(summaryLine, "=", 2)
	if len(parts) < 2 {
		return 0, fmt.Errorf("invalid summary line format (missing '='): %s", summaryLine)
	}
	statsPart := strings.TrimSpace(parts[1])

	// Extract numeric values token (before unit like "ms")
	tokens := strings.Fields(statsPart)
	if len(tokens) == 0 {
		return 0, fmt.Errorf("no numeric values found in stats part: %s", statsPart)
	}
	numbersStr := tokens[0]

	// Split numeric values (format: min/avg/max/[mdev|stddev])
	numberParts := strings.Split(numbersStr, "/")
	if len(numberParts) < 2 {
		return 0, fmt.Errorf("unexpected statistics format (expected min/avg): %s", numbersStr)
	}

	// Parse average value (second field)
	avgStr := strings.TrimSpace(numberParts[1])
	avg, err := strconv.ParseFloat(avgStr, 64)
	if err != nil {
		return 0, fmt.Errorf("failed to parse average latency '%s': %v", avgStr, err)
	}

	return avg, nil
}

func main() {
	if len(os.Args) != 3 {
		fmt.Fprintln(os.Stderr, "Usage: main <host> <count>")
		os.Exit(1)
	}

	host := os.Args[1]
	count, err := strconv.Atoi(os.Args[2])
	if err != nil {
		fmt.Fprintf(os.Stderr, "Error: invalid count - %v\n", err)
		os.Exit(1)
	}

	avg, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Fprintf(os.Stderr, "Error: %v\n", err)
		os.Exit(1)
	}

	// Output average latency with 3 decimal places (milliseconds)
	fmt.Printf("%.3f\n", avg)
}

