// MeasureLatency pings the specified host the given number of times and returns
// the average latency in milliseconds. Uses system 'ping' command with Unix-style flags.
// Returns error if parsing fails, host is unreachable, or command execution fails.
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, fmt.Errorf("ping count must be positive")
	}
	if host == "" {
		return 0, fmt.Errorf("host cannot be empty")
	}

	// Construct ping command for Unix-like systems (Linux/macOS)
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)
	output, cmdErr := cmd.CombinedOutput()

	// Attempt to parse average latency regardless of command exit code
	// (ping may return non-zero on packet loss but still output valid stats)
	avg, parseErr := parsePingOutput(output)
	if parseErr != nil {
		// Provide comprehensive error context including raw output
		return 0, fmt.Errorf("parsing failed: %w; command error: %v; output: %s", 
			parseErr, cmdErr, string(output))
	}
	return avg, nil
}

// parsePingOutput extracts average latency from ping command output
// Handles standard Unix ping summary lines (Linux/macOS):
//   "rtt min/avg/max/mdev = 10.123/20.456/30.789/5.123 ms"
//   "round-trip min/avg/max/stddev = 1.234/5.678/9.012/3.456 ms"
func parsePingOutput(output []byte) (float64, error) {
	lines := strings.Split(string(output), "\n")
	var summaryLine string

	// Search from end (summary appears at end of output)
	for i := len(lines) - 1; i >= 0; i-- {
		if strings.Contains(lines[i], "min/avg/max") {
			summaryLine = lines[i]
			break
		}
	}

	if summaryLine == "" {
		return 0, fmt.Errorf("summary line containing 'min/avg/max' not found")
	}

	// Split to isolate values section (after '=')
	parts := strings.SplitN(summaryLine, "=", 2)
	if len(parts) < 2 {
		return 0, fmt.Errorf("invalid summary format: missing '=' separator")
	}

	valuesSection := strings.TrimSpace(parts[1])
	if valuesSection == "" {
		return 0, fmt.Errorf("empty values section after '='")
	}

	// Extract numeric values block (before unit like "ms")
	valueTokens := strings.Split(valuesSection, " ")
	if len(valueTokens) == 0 || valueTokens[0] == "" {
		return 0, fmt.Errorf("no numeric values found in summary")
	}

	// Split numeric block (e.g., "10.123/20.456/30.789/5.123")
	numbers := strings.Split(valueTokens[0], "/")
	if len(numbers) < 2 {
		return 0, fmt.Errorf("expected at least min and avg values")
	}

	// Parse average value (second field)
	avg, err := strconv.ParseFloat(numbers[1], 64)
	if err != nil {
		return 0, fmt.Errorf("invalid average value '%s': %w", numbers[1], err)
	}

	return avg, nil
}

