package main

import (
	"errors"
	"fmt"
	"os/exec"
	"regexp"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host the given number of times and returns the average latency in milliseconds.
// It uses the system 'ping' command via os/exec and parses the output to extract the average RTT.
// Note: This implementation is optimized for Linux systems where ping output contains "rtt min/avg/max/mdev".
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}

	// Execute ping directly without shell invocation for security and portability
	// Uses separate arguments to avoid shell injection risks and quoting issues
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("ping execution failed: %w (output: %s)", err, string(output))
	}

	// Parse output to find RTT statistics line (Linux format)
	outputStr := string(output)
	lines := strings.Split(outputStr, "\n")
	var statsLine string
	for _, line := range lines {
		if strings.Contains(line, "rtt min/avg/max") {
			statsLine = line
			break
		}
	}

	if statsLine == "" {
		return 0, errors.New("RTT statistics line not found in ping output (requires Linux-compatible ping)")
	}

	// Flexible regex to handle varying digit counts and decimal formats
	// Matches patterns like: rtt min/avg/max/mdev = 12.345/23.456/34.567/5.678 ms
	re := regexp.MustCompile(`rtt min/avg/max/mdev = [\d.]+/([\d.]+)/[\d.]+/[\d.]+ ms`)
	matches := re.FindStringSubmatch(statsLine)
	if len(matches) < 2 {
		return 0, fmt.Errorf("failed to parse average latency from line: %s", statsLine)
	}

	avg, err := strconv.ParseFloat(matches[1], 64)
	if err != nil {
		return 0, fmt.Errorf("invalid average latency value '%s': %w", matches[1], err)
	}

	return avg, nil
}

