package main

import (
	"fmt"
	"os"
	"os/exec"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host the given number of times and returns
// the average round-trip latency in milliseconds. Uses system ping command.
// Designed for Unix-like systems (Linux/macOS) where ping uses -c flag and
// outputs statistics containing "min/avg/max".
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, fmt.Errorf("count must be a positive integer")
	}
	if host == "" {
		return 0, fmt.Errorf("host cannot be empty")
	}

	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("ping command failed: %w, output: %s", err, string(output))
	}

	lines := strings.Split(string(output), "\n")
	for _, line := range lines {
		if strings.Contains(line, "min/avg/max") {
			eqIdx := strings.Index(line, "=")
			if eqIdx == -1 {
				continue
			}
			statsPart := strings.TrimSpace(line[eqIdx+1:])
			if spaceIdx := strings.Index(statsPart, " "); spaceIdx != -1 {
				statsPart = statsPart[:spaceIdx]
			}
			parts := strings.Split(statsPart, "/")
			if len(parts) < 2 {
				continue
			}
			avgStr := parts[1]
			avg, parseErr := strconv.ParseFloat(avgStr, 64)
			if parseErr != nil {
				return 0, fmt.Errorf("failed to parse average latency value '%s': %w", avgStr, parseErr)
			}
			return avg, nil
		}
	}

	return 0, fmt.Errorf("latency statistics not found in ping output. Full output: %s", string(output))
}

func main() {
	if len(os.Args) != 3 {
		fmt.Fprintf(os.Stderr, "Usage: %s <host> <count>\n", os.Args[0])
		os.Exit(1)
	}

	host := os.Args[1]
	count, err := strconv.Atoi(os.Args[2])
	if err != nil {
		fmt.Fprintf(os.Stderr, "Error: invalid count - %v\n", err)
		os.Exit(1)
	}

	avg, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Fprintf(os.Stderr, "Error: %v\n", err)
		os.Exit(1)
	}

	fmt.Printf("%.3f\n", avg)
}

