// MeasureLatency pings the specified host the given number of times and returns
// the average latency in milliseconds. Designed for Unix-like systems (Linux/macOS)
// where ping output contains "min/avg/max" statistics. Uses system ping command
// via os/exec.
func MeasureLatency(host string, count int) (float64, error) {
	// Validate inputs
	if count <= 0 {
		return 0, fmt.Errorf("count must be a positive integer")
	}
	if host == "" {
		return 0, fmt.Errorf("host cannot be empty")
	}

	// Build ping command (Unix-style: -c for count)
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)
	var stdout, stderr bytes.Buffer
	cmd.Stdout = &stdout
	cmd.Stderr = &stderr

	// Execute ping command
	if err := cmd.Run(); err != nil {
		errMsg := strings.TrimSpace(stderr.String())
		if errMsg == "" {
			errMsg = err.Error()
		}
		return 0, fmt.Errorf("ping command failed: %s", errMsg)
	}

	// Parse stdout for statistics line containing "min/avg/max"
	output := stdout.String()
	var statsLine string
	for _, line := range strings.Split(output, "\n") {
		if strings.Contains(line, "min/avg/max") {
			statsLine = line
			break
		}
	}
	if statsLine == "" {
		return 0, fmt.Errorf("could not find latency statistics in ping output")
	}

	// Extract values section (after "=")
	eqIdx := strings.Index(statsLine, "=")
	if eqIdx == -1 {
		return 0, fmt.Errorf("invalid statistics line format: missing '='")
	}
	valuesPart := strings.TrimSpace(statsLine[eqIdx+1:])
	valuesPart = strings.TrimRight(valuesPart, " ms")
	valuesPart = strings.TrimSpace(valuesPart)

	// Split values (format: min/avg/max/[mdev|stddev])
	valueTokens := strings.Split(valuesPart, "/")
	if len(valueTokens) < 2 {
		return 0, fmt.Errorf("unexpected statistics format: expected at least 'min/avg'")
	}
	avgStr := valueTokens[1] // Average is second token

	// Convert to float64
	avg, err := strconv.ParseFloat(avgStr, 64)
	if err != nil {
		return 0, fmt.Errorf("failed to parse average latency value '%s': %w", avgStr, err)
	}
	return avg, nil
}

func main() {
	if len(os.Args) != 3 {
		fmt.Fprintln(os.Stderr, "Usage: main <host> <count>")
		fmt.Fprintln(os.Stderr, "Example: main example.com 4")
		os.Exit(1)
	}

	host := os.Args[1]
	count, err := strconv.Atoi(os.Args[2])
	if err != nil {
		fmt.Fprintf(os.Stderr, "Invalid count: %v\n", err)
		os.Exit(1)
	}

	avg, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Fprintf(os.Stderr, "Error: %v\n", err)
		os.Exit(1)
	}

	// Output average latency with 3 decimal precision (standard for ping)
	fmt.Printf("%.3f\n", avg)
}

