package main

import (
	"errors"
	"fmt"
	"os/exec"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host the given number of times and returns the average latency in milliseconds.
// It uses the system 'ping' command via os/exec and parses the output to extract the average RTT.
// This implementation is designed for Unix-like systems where 'ping' uses '-c' flag and outputs statistics in standard format.
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}

	// Execute ping directly without shell to prevent command injection
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("ping command failed: %w (output: %s)", err, string(output))
	}

	// Search for statistics line case-insensitively (handles locale variations)
	outputStr := string(output)
	lines := strings.Split(outputStr, "\n")
	var statsLine string
	for _, line := range lines {
		if strings.Contains(strings.ToLower(line), "rtt min/avg/max") {
			statsLine = line
			break
		}
	}

	if statsLine == "" {
		return 0, errors.New("RTT statistics line not found in ping output")
	}

	// Parse statistics line robustly without regex
	eqIndex := strings.Index(statsLine, "=")
	if eqIndex == -1 {
		return 0, errors.New("statistics line missing '=' separator")
	}

	// Extract numeric values segment (handles extra spaces)
	afterEq := strings.TrimSpace(statsLine[eqIndex+1:])
	valueFields := strings.Fields(afterEq)
	if len(valueFields) == 0 {
		return 0, errors.New("no numeric values found after '=' in statistics line")
	}

	// Split min/avg/max/mdev values
	numberParts := strings.Split(valueFields[0], "/")
	if len(numberParts) < 2 {
		return 0, errors.New("unexpected statistics value format (expected min/avg/...)")
	}

	avgStr := strings.TrimSpace(numberParts[1])
	avg, err := strconv.ParseFloat(avgStr, 64)
	if err != nil {
		return 0, fmt.Errorf("failed to parse average latency value '%s': %w", avgStr, err)
	}

	return avg, nil
}

