package main

import (
	"errors"
	"fmt"
	"os/exec"
	"regexp"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host the given number of times and returns the average latency in milliseconds.
// It uses the system 'ping' command via os/exec and parses the output to extract the average RTT.
// Security hardening: 
//   - Avoids shell invocation to prevent command injection
//   - Validates host input to prevent option injection
//   - Uses -- separator for ping arguments
func MeasureLatency(host string, count int) (float64, error) {
	// Validate host input thoroughly
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if strings.HasPrefix(host, "-") {
		return 0, errors.New("host cannot start with dash character (security restriction)")
	}
	if strings.Contains(host, "\x00") {
		return 0, errors.New("host cannot contain null bytes")
	}
	if strings.ContainsAny(host, "\n\r\t") {
		return 0, errors.New("host cannot contain control characters or whitespace")
	}

	// Validate count
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}
	if count > 100 {
		return 0, errors.New("count exceeds maximum allowed value (100)")
	}

	// Execute ping directly without shell invocation
	// Using "--" separator prevents host from being interpreted as option
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), "--", host)
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("ping execution failed: %w (output: %s)", err, string(output))
	}

	// Parse RTT statistics from output
	outputStr := string(output)
	lines := strings.Split(outputStr, "\n")
	var statsLine string
	for _, line := range lines {
		if strings.Contains(line, "rtt min/avg/max") {
			statsLine = line
			break
		}
	}

	if statsLine == "" {
		return 0, errors.New("could not find RTT statistics in ping output")
	}

	// Extract average latency using regex
	// Example line: rtt min/avg/max/mdev = 12.345/23.456/34.567/5.678 ms
	re := regexp.MustCompile(`rtt min/avg/max/mdev = \d+\.\d+/([\d.]+)/\d+\.\d+/\d+\.\d+ ms`)
	matches := re.FindStringSubmatch(statsLine)
	if len(matches) < 2 {
		// Fallback for systems using "stddev" instead of "mdev" (e.g., macOS)
		reFallback := regexp.MustCompile(`round-trip min/avg/max/stddev = \d+\.\d+/([\d.]+)/\d+\.\d+/\d+\.\d+ ms`)
		matches = reFallback.FindStringSubmatch(statsLine)
		if len(matches) < 2 {
			return 0, errors.New("failed to parse average latency from ping output")
		}
	}

	avgStr := matches[1]
	avg, err := strconv.ParseFloat(avgStr, 64)
	if err != nil {
		return 0, fmt.Errorf("failed to convert average latency to float: %w", err)
	}

	return avg, nil
}

