import (
	"fmt"
	"os"
	"os/exec"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host the given number of times and returns
// the average latency in milliseconds. Uses system 'ping' command with -c flag
// (Unix-like systems). Returns error if validation fails, command fails, or
// statistics cannot be parsed.
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, fmt.Errorf("host cannot be empty")
	}
	if count <= 0 {
		return 0, fmt.Errorf("count must be a positive integer")
	}

	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("ping command failed: %w. Output: %s", err, string(output))
	}

	outputStr := string(output)
	lines := strings.Split(outputStr, "\n")

	// Search backward for statistics line containing latency summary
	for i := len(lines) - 1; i >= 0; i-- {
		line := lines[i]
		// Match standard Unix ping summary lines (Linux/macOS):
		// "rtt min/avg/max/mdev = ..." or "round-trip min/avg/max/stddev = ..."
		if (strings.Contains(line, "min/avg/max") || 
		    (strings.Contains(line, "avg") && strings.Contains(line, "/"))) && 
		   strings.Contains(line, "ms") {

			for _, field := range strings.Fields(line) {
				if strings.Contains(field, "/") && strings.Contains(field, ".") {
					parts := strings.Split(field, "/")
					if len(parts) >= 2 {
						if avg, parseErr := strconv.ParseFloat(parts[1], 64); parseErr == nil {
							return avg, nil
						}
					}
				}
			}
			return 0, fmt.Errorf("found statistics line but failed to parse average: %s", line)
		}
	}

	return 0, fmt.Errorf("latency statistics not found in ping output. Full output: %s", outputStr)
}

func main() {
	if len(os.Args) != 3 {
		fmt.Fprintf(os.Stderr, "Usage: %s <host> <count>\n", os.Args[0])
		os.Exit(1)
	}

	host := os.Args[1]
	count, err := strconv.Atoi(os.Args[2])
	if err != nil {
		fmt.Fprintf(os.Stderr, "Invalid count: %v\n", err)
		os.Exit(1)
	}

	avg, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Fprintf(os.Stderr, "Error: %v\n", err)
		os.Exit(1)
	}

	fmt.Printf("%.3f\n", avg)
}

