package main

import (
	"fmt"
	"os"
	"os/exec"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host the given number of times and returns
// the average latency in milliseconds. Uses system ping command with quiet mode
// for reliable parsing of summary statistics.
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, fmt.Errorf("count must be a positive integer")
	}

	// Construct ping command: -c for count, -q for quiet mode (summary only)
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), "-q", host)
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("ping command failed: %w, output: %s", err, string(output))
	}

	// Process output to find statistics line
	lines := strings.Split(strings.TrimSpace(string(output)), "\n")
	if len(lines) == 0 {
		return 0, fmt.Errorf("empty ping output")
	}

	// Last line contains rtt statistics (min/avg/max/mdev)
	statsLine := lines[len(lines)-1]
	eqIdx := strings.Index(statsLine, "=")
	if eqIdx == -1 {
		return 0, fmt.Errorf("statistics line missing '=': %s", statsLine)
	}

	// Extract values after '=' and split by '/'
	statsPart := strings.TrimSpace(statsLine[eqIdx+1:])
	values := strings.Split(statsPart, "/")
	if len(values) < 2 {
		return 0, fmt.Errorf("unexpected statistics format: %s", statsPart)
	}

	// Clean and parse average value (second field after min)
	avgStr := strings.TrimSpace(values[1])
	cleaned := strings.Map(func(r rune) rune {
		if (r >= '0' && r <= '9') || r == '.' {
			return r
		}
		return -1
	}, avgStr)

	if cleaned == "" {
		return 0, fmt.Errorf("failed to extract numeric value from '%s'", avgStr)
	}

	avg, parseErr := strconv.ParseFloat(cleaned, 64)
	if parseErr != nil {
		return 0, fmt.Errorf("invalid average value '%s': %w", cleaned, parseErr)
	}

	return avg, nil
}

func main() {
	if len(os.Args) != 3 {
		fmt.Fprintf(os.Stderr, "Usage: %s <host> <count>\n", os.Args[0])
		os.Exit(1)
	}

	host := os.Args[1]
	count, err := strconv.Atoi(os.Args[2])
	if err != nil {
		fmt.Fprintf(os.Stderr, "Error: invalid count '%s' - must be integer\n", os.Args[2])
		os.Exit(1)
	}

	latency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Fprintf(os.Stderr, "Latency measurement failed: %v\n", err)
		os.Exit(1)
	}

	fmt.Printf("%.3f\n", latency)
}

