package main

import (
	"errors"
	"fmt"
	"os/exec"
	"regexp"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host the given number of times and returns the average latency in milliseconds.
// It uses the system 'ping' command via os/exec and parses the output to extract the average RTT.
// Security: Direct argument passing avoids shell injection vulnerabilities.
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}

	// CRITICAL FIX: Avoid shell invocation entirely to prevent command injection.
	// Pass arguments directly to ping command without shell interpretation.
	// Host string is passed as a single argument - OS handles validation.
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("ping execution failed: %w (output: %s)", err, string(output))
	}

	// Parse RTT statistics line
	outputStr := string(output)
	lines := strings.Split(outputStr, "\n")
	var statsLine string
	for _, line := range lines {
		// Match standard Linux ping output format
		if strings.Contains(line, "rtt min/avg/max") {
			statsLine = line
			break
		}
	}

	if statsLine == "" {
		// Attempt macOS/BSD format fallback (more robust parsing)
		for _, line := range lines {
			if strings.Contains(line, "round-trip min/avg/max") {
				statsLine = line
				break
			}
		}
		if statsLine == "" {
			return 0, errors.New("RTT statistics not found in ping output (unsupported ping format)")
		}
	}

	// Extract average latency with flexible regex to handle minor format variations
	// Handles: "rtt min/avg/max/mdev = X/Y/Z/W ms" (Linux) and "round-trip min/avg/max/stddev = X/Y/Z/W ms" (macOS)
	re := regexp.MustCompile(`(?:rtt|round-trip)\s+(?:min/avg/max(?:/mdev|/stddev)?)\s*=\s*\d+(?:\.\d+)?/\s*([\d.]+)\s*/`)
	matches := re.FindStringSubmatch(statsLine)
	if len(matches) < 2 {
		return 0, fmt.Errorf("failed to parse average latency from: %q", statsLine)
	}

	avg, err := strconv.ParseFloat(matches[1], 64)
	if err != nil {
		return 0, fmt.Errorf("invalid average latency value '%s': %w", matches[1], err)
	}

	return avg, nil
}

