package main

import (
	"fmt"
	"os"
	"os/exec"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host the given number of times and returns
// the average latency in milliseconds. Uses system 'ping' command with Unix-style flags.
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, fmt.Errorf("count must be a positive integer")
	}
	if host == "" {
		return 0, fmt.Errorf("host cannot be empty")
	}

	// Execute ping command (Unix-style: -c for count)
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("ping command failed: %w, output: %s", err, string(output))
	}

	// Parse ping output for latency statistics line containing "min/avg/max"
	outputStr := string(output)
	for _, line := range strings.Split(outputStr, "\n") {
		if strings.Contains(line, "min/avg/max") {
			// Extract statistics portion after "="
			parts := strings.Split(line, "=")
			if len(parts) < 2 {
				continue
			}
			stats := strings.TrimSpace(parts[1])
			stats = strings.TrimSuffix(stats, " ms")

			// Split statistics values (min/avg/max/...)
			values := strings.Split(stats, "/")
			if len(values) < 2 {
				continue
			}

			// Parse average value (second field)
			avg, parseErr := strconv.ParseFloat(values[1], 64)
			if parseErr != nil {
				return 0, fmt.Errorf("failed to parse average latency value '%s': %w", values[1], parseErr)
			}
			return avg, nil
		}
	}

	return 0, fmt.Errorf("latency statistics not found in ping output. Full output:\n%s", outputStr)
}

func main() {
	if len(os.Args) != 3 {
		fmt.Fprintln(os.Stderr, "Usage: main <host> <count>")
		fmt.Fprintln(os.Stderr, "Example: main example.com 4")
		os.Exit(1)
	}

	host := os.Args[1]
	count, err := strconv.Atoi(os.Args[2])
	if err != nil {
		fmt.Fprintf(os.Stderr, "Error: invalid count '%s' - must be a positive integer\n", os.Args[2])
		os.Exit(1)
	}

	avgLatency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Fprintf(os.Stderr, "Error: %v\n", err)
		os.Exit(1)
	}

	// Output average latency with 3 decimal places (standard for latency measurements)
	fmt.Printf("%.3f\n", avgLatency)
}

