package main

import (
	"fmt"
	"os"
	"os/exec"
	"regexp"
	"strconv"
)

// MeasureLatency pings the specified host the given number of times and returns
// the average latency of received replies in milliseconds. Uses system ping command.
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, fmt.Errorf("count must be a positive integer")
	}

	// Execute ping command with count parameter (Unix-style: Linux/macOS)
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)
	output, err := cmd.CombinedOutput()

	// Even if command fails (non-zero exit), attempt parsing if output exists
	// Critical errors (unknown host, network unreachable) will have no valid replies
	re := regexp.MustCompile(`time=([\d.]+)\s*ms`)
	matches := re.FindAllStringSubmatch(string(output), -1)

	if len(matches) == 0 {
		if err != nil {
			return 0, fmt.Errorf("ping failed: %w; output: %s", err, string(output))
		}
		return 0, fmt.Errorf("no valid ping replies found in output")
	}

	var sum float64
	for _, match := range matches {
		if len(match) < 2 {
			continue
		}
		t, parseErr := strconv.ParseFloat(match[1], 64)
		if parseErr != nil {
			return 0, fmt.Errorf("failed to parse time value '%s': %v", match[1], parseErr)
		}
		sum += t
	}

	avg := sum / float64(len(matches))
	return avg, nil
}

func main() {
	if len(os.Args) != 3 {
		fmt.Fprintf(os.Stderr, "Usage: %s <host> <count>\n", os.Args[0])
		os.Exit(1)
	}

	count, err := strconv.Atoi(os.Args[2])
	if err != nil {
		fmt.Fprintf(os.Stderr, "Invalid count: %v\n", err)
		os.Exit(1)
	}

	avg, err := MeasureLatency(os.Args[1], count)
	if err != nil {
		fmt.Fprintf(os.Stderr, "Error: %v\n", err)
		os.Exit(1)
	}

	fmt.Printf("%.3f\n", avg)
}

