package main

import (
	"errors"
	"fmt"
	"os/exec"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host the given number of times and returns the average latency in milliseconds.
// It uses the system 'ping' command via os/exec and parses the output to extract the average RTT.
// Note: This implementation is optimized for Linux systems where ping output follows the format:
// "rtt min/avg/max/mdev = X.XXX/Y.YYY/Z.ZZZ/W.WWW ms"
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}

	// Execute ping directly without shell to avoid injection risks and improve portability
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("ping command failed: %w (output: %s)", err, string(output))
	}

	// Search for RTT statistics line (Linux format)
	outputStr := string(output)
	var statsLine string
	for _, line := range strings.Split(outputStr, "\n") {
		if strings.Contains(line, "rtt min/avg/max") {
			statsLine = line
			break
		}
	}

	if statsLine == "" {
		return 0, errors.New("RTT statistics line not found in ping output (ensure Linux-compatible ping is used)")
	}

	// Parse statistics line using robust string splitting (handles integer/float values)
	parts := strings.SplitN(statsLine, "=", 2)
	if len(parts) < 2 {
		return 0, errors.New("invalid RTT statistics line format: missing '=' separator")
	}

	numbersSection := strings.TrimSpace(parts[1])
	if numbersSection == "" {
		return 0, errors.New("no numeric data found after '=' in RTT statistics line")
	}

	// Extract numeric values (ignore unit suffixes like "ms")
	numberTokens := strings.Split(numbersSection, " ")
	numberStr := numberTokens[0] // Format: "min/avg/max[/mdev]"
	values := strings.Split(numberStr, "/")
	if len(values) < 2 {
		return 0, errors.New("unexpected RTT value format: expected at least 'min/avg'")
	}

	avgStr := strings.TrimSpace(values[1])
	avg, err := strconv.ParseFloat(avgStr, 64)
	if err != nil {
		return 0, fmt.Errorf("failed to parse average latency value '%s': %w", avgStr, err)
	}

	return avg, nil
}

