package main

import (
	"bytes"
	"fmt"
	"os/exec"
	"runtime"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host the given number of times and returns
// the average latency in milliseconds. Uses OS-specific ping command execution
// and output parsing.
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, fmt.Errorf("count must be positive")
	}
	if host == "" {
		return 0, fmt.Errorf("host cannot be empty")
	}

	// Build OS-specific ping command
	var cmd *exec.Cmd
	if runtime.GOOS == "windows" {
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	} else {
		// -q flag enables quiet mode for concise summary output (Linux/macOS)
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), "-q", host)
	}

	var stdout, stderr bytes.Buffer
	cmd.Stdout = &stdout
	cmd.Stderr = &stderr

	if err := cmd.Run(); err != nil {
		return 0, fmt.Errorf("ping command failed: %w, stderr: %s", err, stderr.String())
	}

	output := stdout.String()
	if runtime.GOOS == "windows" {
		return parseWindowsPingOutput(output)
	}
	return parseUnixPingOutput(output)
}

// parseUnixPingOutput extracts average latency from Unix-like ping output
// (Linux/macOS). Looks for line containing "min/avg/max" pattern.
func parseUnixPingOutput(output string) (float64, error) {
	for _, line := range strings.Split(output, "\n") {
		if strings.Contains(line, "min/avg/max") {
			parts := strings.Split(line, "=")
			if len(parts) < 2 {
				continue
			}
			stats := strings.TrimSpace(parts[1])
			stats = strings.TrimRight(stats, " ms") // Remove trailing units
			values := strings.Split(stats, "/")
			if len(values) < 2 {
				continue
			}
			avg, err := strconv.ParseFloat(strings.TrimSpace(values[1]), 64)
			if err != nil {
				return 0, fmt.Errorf("failed to parse average latency value: %w", err)
			}
			return avg, nil
		}
	}
	return 0, fmt.Errorf("could not find latency statistics in ping output")
}

// parseWindowsPingOutput extracts average latency from Windows ping output.
// Looks for line containing "Average =" pattern.
func parseWindowsPingOutput(output string) (float64, error) {
	for _, line := range strings.Split(output, "\n") {
		if strings.Contains(line, "Average =") {
			parts := strings.Split(line, "Average =")
			if len(parts) < 2 {
				continue
			}
			avgStr := strings.TrimSpace(parts[1])
			avgStr = strings.TrimSuffix(avgStr, "ms")
			avgStr = strings.TrimSpace(avgStr)
			avg, err := strconv.ParseFloat(avgStr, 64)
			if err != nil {
				return 0, fmt.Errorf("failed to parse Windows average latency value: %w", err)
			}
			return avg, nil
		}
	}
	return 0, fmt.Errorf("could not find average latency in Windows ping output")
}

