import (
	"fmt"
	"os"
	"os/exec"
	"strconv"
	"strings"
	"flag"
)

// MeasureLatency pings the specified host the given number of times and returns the average latency in milliseconds.
// Uses Linux ping command format and output parsing. Requires ping command to be available in PATH.
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, fmt.Errorf("ping count must be positive")
	}
	if host == "" {
		return 0, fmt.Errorf("host cannot be empty")
	}

	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)
	output, cmdErr := cmd.CombinedOutput()

	avg, parseErr := parseLinuxPingOutput(output)
	if parseErr != nil {
		return 0, fmt.Errorf("failed to parse ping output: %w. Command error: %v, Output: %s", 
			parseErr, cmdErr, string(output))
	}
	return avg, nil
}

// parseLinuxPingOutput extracts average latency from Linux ping command output
func parseLinuxPingOutput(output []byte) (float64, error) {
	lines := strings.Split(string(output), "\n")
	for _, line := range lines {
		if strings.Contains(line, "min/avg/max") {
			tokens := strings.Fields(line)
			for i, token := range tokens {
				if token == "=" && i+1 < len(tokens) {
					numbers := strings.Split(tokens[i+1], "/")
					if len(numbers) >= 2 {
						avgStr := numbers[1]
						avg, err := strconv.ParseFloat(avgStr, 64)
						if err != nil {
							return 0, fmt.Errorf("invalid average value '%s': %w", avgStr, err)
						}
						return avg, nil
					}
				}
			}
			return 0, fmt.Errorf("statistics line found but average value missing")
		}
	}
	return 0, fmt.Errorf("ping statistics line not found in output")
}

func main() {
	host := flag.String("host", "", "Target host to ping (required)")
	count := flag.Int("count", 4, "Number of ping attempts (default: 4)")
	flag.Parse()

	if *host == "" {
		fmt.Fprintln(os.Stderr, "Error: host is required")
		flag.Usage()
		os.Exit(1)
	}

	avg, err := MeasureLatency(*host, *count)
	if err != nil {
		fmt.Fprintf(os.Stderr, "Error: %v\n", err)
		os.Exit(1)
	}

	fmt.Printf("%.3f\n", avg)
}

