package main

import (
	"errors"
	"fmt"
	"os/exec"
	"regexp"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host the given number of times and returns the average latency in milliseconds.
// It uses the system 'ping' command via os/exec and parses the output to extract the average RTT.
// Note: This implementation is optimized for Linux systems where ping output follows the format:
// "rtt min/avg/max/mdev = <min>/<avg>/<max>/<mdev> ms"
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}

	// Execute ping command directly (no shell wrapper) for security and portability
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("ping command failed: %w (output: %s)", err, string(output))
	}

	// Search for RTT statistics line (Linux format)
	outputStr := string(output)
	lines := strings.Split(outputStr, "\n")
	var statsLine string
	for _, line := range lines {
		if strings.Contains(line, "rtt min/avg/max") {
			statsLine = line
			break
		}
	}

	if statsLine == "" {
		return 0, errors.New("RTT statistics line not found in ping output")
	}

	// Robust regex to handle:
	// - Integer or float values (e.g., "12" or "12.345")
	// - Optional whitespace around separators
	// - Captures ONLY the average value (second numeric field)
	re := regexp.MustCompile(`rtt min/avg/max/mdev\s*=\s*\d+(?:\.\d+)?\s*/\s*(\d+(?:\.\d+)?)\s*/`)
	matches := re.FindStringSubmatch(statsLine)
	if len(matches) < 2 {
		return 0, fmt.Errorf("failed to parse average latency from stats line: %s", statsLine)
	}

	avg, err := strconv.ParseFloat(matches[1], 64)
	if err != nil {
		return 0, fmt.Errorf("invalid average latency value '%s': %w", matches[1], err)
	}

	return avg, nil
}

