	re := regexp.MustCompile(`time=([0-9.]+)\s*ms`)
	matches := re.FindAllStringSubmatch(string(output), -1)

	if len(matches) != count {
		return 0, fmt.Errorf("expected %d responses, found %d in output", count, len(matches))
	}

	var total float64
	for _, match := range matches {
		if len(match) < 2 {
			continue
		}
		t, parseErr := strconv.ParseFloat(match[1], 64)
		if parseErr != nil {
			return 0, fmt.Errorf("failed to parse time value '%s': %w", match[1], parseErr)
		}
		total += t
	}

	return total / float64(count), nil
}

func main() {
	if len(os.Args) != 3 {
		fmt.Fprintln(os.Stderr, "Usage: latency-tool <host> <count>")
		fmt.Fprintln(os.Stderr, "Example: latency-tool example.com 4")
		os.Exit(1)
	}

	host := os.Args[1]
	count, err := strconv.Atoi(os.Args[2])
	if err != nil {
		fmt.Fprintf(os.Stderr, "Invalid count: %v\n", err)
		os.Exit(1)
	}

	avgLatency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Fprintf(os.Stderr, "Error: %v\n", err)
		os.Exit(1)
	}

	fmt.Printf("%.2f\n", avgLatency)
}

