fix.generatedCode:
package main

import (
	"errors"
	"fmt"
	"os/exec"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host the given number of times and returns the average latency in milliseconds.
// It uses the system 'ping' command via os/exec and parses the output to extract the average RTT.
// Note: This implementation is designed for Linux systems where ping output contains "rtt min/avg/max/mdev".
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}

	// Execute ping command directly without shell to prevent injection vulnerabilities
	// and ensure proper argument handling across environments
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("failed to execute ping: %w (output: %s)", err, string(output))
	}

	// Search for RTT statistics line in ping output (Linux format)
	outputStr := string(output)
	lines := strings.Split(outputStr, "\n")
	var statsLine string
	for _, line := range lines {
		if strings.Contains(line, "rtt min/avg/max") {
			statsLine = line
			break
		}
	}

	if statsLine == "" {
		return 0, errors.New("could not find RTT statistics line in ping output")
	}

	// Parse statistics line: "rtt min/avg/max/mdev = 12.345/23.456/34.567/5.678 ms"
	parts := strings.SplitN(statsLine, "=", 2)
	if len(parts) != 2 {
		return 0, errors.New("RTT statistics line missing '=' separator")
	}

	rightPart := strings.TrimSpace(parts[1])
	numUnitParts := strings.SplitN(rightPart, " ", 2)
	if len(numUnitParts) == 0 || numUnitParts[0] == "" {
		return 0, errors.New("no numeric values found after '=' in RTT statistics line")
	}

	numValues := strings.Split(numUnitParts[0], "/")
	if len(numValues) < 2 {
		return 0, errors.New("expected at least min and avg values in RTT statistics")
	}

	avgStr := strings.TrimSpace(numValues[1])
	avg, err := strconv.ParseFloat(avgStr, 64)
	if err != nil {
		return 0, fmt.Errorf("failed to parse average latency value '%s': %w", avgStr, err)
	}

	return avg, nil
}

