package main

import (
	"bufio"
	"fmt"
	"os"
	"os/exec"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host the given number of times and returns
// the average latency in milliseconds. Uses system ping command (Unix-style).
// Returns error if host is unreachable, output is unparsable, or inputs are invalid.
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, fmt.Errorf("host cannot be empty")
	}
	if count < 1 {
		return 0, fmt.Errorf("count must be at least 1")
	}

	// Construct ping command for Unix-like systems (Linux/macOS)
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("ping command failed: %w, output: %s", err, string(output))
	}

	// Parse output for latency statistics line containing "min/avg/max"
	scanner := bufio.NewScanner(strings.NewReader(string(output)))
	for scanner.Scan() {
		line := scanner.Text()
		if strings.Contains(strings.ToLower(line), "min/avg/max") {
			for _, token := range strings.Fields(line) {
				if strings.Contains(token, "/") {
					parts := strings.Split(token, "/")
					if len(parts) >= 2 {
						if avg, parseErr := strconv.ParseFloat(parts[1], 64); parseErr == nil {
							return avg, nil
						}
					}
				}
			}
			return 0, fmt.Errorf("found statistics line but failed to parse average value: %s", line)
		}
	}

	return 0, fmt.Errorf("latency statistics not found in ping output")
}

func main() {
	if len(os.Args) != 3 {
		fmt.Fprintf(os.Stderr, "Usage: %s <host> <count>\n", os.Args[0])
		os.Exit(1)
	}

	host := os.Args[1]
	count, err := strconv.Atoi(os.Args[2])
	if err != nil {
		fmt.Fprintf(os.Stderr, "Invalid count: %v\n", err)
		os.Exit(1)
	}

	avgLatency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Fprintf(os.Stderr, "Error: %v\n", err)
		os.Exit(1)
	}

	// Output average latency formatted to 3 decimal places
	fmt.Printf("%.3f\n", avgLatency)
}

