package main

import (
	"fmt"
	"os"
	"os/exec"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host the given number of times and returns
// the average round-trip latency in milliseconds. Uses system ping command with
// Unix-style arguments (-c flag). Returns error if ping fails, no replies received,
// or output cannot be parsed.
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, fmt.Errorf("count must be a positive integer")
	}

	// Execute ping command (Unix-style: -c for count)
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)
	outputBytes, err := cmd.CombinedOutput()
	output := string(outputBytes)

	// Check command execution failure (non-zero exit code or OS error)
	if err != nil {
		return 0, fmt.Errorf("ping command failed: %w, output: %s", err, strings.TrimSpace(output))
	}

	// Search output backwards for statistics line containing latency metrics
	lines := strings.Split(output, "\n")
	var statsLine string
	for i := len(lines) - 1; i >= 0; i-- {
		if strings.Contains(lines[i], "min/avg/max") {
			statsLine = strings.TrimSpace(lines[i])
			break
		}
	}

	if statsLine == "" {
		return 0, fmt.Errorf("statistics line containing 'min/avg/max' not found in ping output")
	}

	// Extract the numeric values field (contains slashes)
	fields := strings.Fields(statsLine)
	var numbersField string
	for _, field := range fields {
		if strings.Contains(field, "/") && strings.Contains(field, ".") {
			numbersField = field
			break
		}
	}

	if numbersField == "" {
		return 0, fmt.Errorf("could not locate latency values field in statistics line")
	}

	// Split numeric values and extract average (second value)
	parts := strings.Split(numbersField, "/")
	if len(parts) < 2 {
		return 0, fmt.Errorf("unexpected latency values format: expected min/avg/..., got %d parts", len(parts))
	}

	avgStr := parts[1]
	avg, parseErr := strconv.ParseFloat(avgStr, 64)
	if parseErr != nil {
		return 0, fmt.Errorf("failed to parse average latency value '%s': %w", avgStr, parseErr)
	}

	return avg, nil
}

func main() {
	if len(os.Args) != 3 {
		fmt.Fprintln(os.Stderr, "Usage: latency_tool <host> <count>")
		fmt.Fprintln(os.Stderr, "Example: latency_tool example.com 4")
		os.Exit(1)
	}

	host := os.Args[1]
	count, err := strconv.Atoi(os.Args[2])
	if err != nil || count <= 0 {
		fmt.Fprintf(os.Stderr, "Error: count must be a positive integer\n")
		os.Exit(1)
	}

	avg, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Fprintf(os.Stderr, "Measurement failed: %v\n", err)
		os.Exit(1)
	}

	// Output average latency with 2 decimal places (milliseconds)
	fmt.Printf("%.2f\n", avg)
}

